// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decode a base64 cursor back into { created_at, id }.
 * Throws on malformed input so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    // Validate the decoded shape — don't trust client-supplied data.
    if (
        !parsed ||
        typeof parsed.created_at !== 'string' ||
        (typeof parsed.id !== 'number' && typeof parsed.id !== 'string') ||
        Number.isNaN(Date.parse(parsed.created_at))
    ) {
        throw new Error('Invalid cursor contents');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

async function getPosts(req, res) {
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const { after } = req.query;

    // Build the query. We fetch limit + 1 rows (the "N+1 trick") to detect
    // whether another page exists without running a separate COUNT.
    let sql;
    let params;

    if (after !== undefined && after !== '') {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }

        // Keyset/seek predicate matching ORDER BY created_at DESC, id DESC.
        // Row tuples are compared lexicographically: a row is "after" the
        // cursor if its created_at is older, or equal created_at with a
        // smaller id. The (created_at, id) tuple comparison expresses this
        // cleanly and is index-friendly.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1::timestamptz, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // No cursor → first page, no keyset filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // If we got limit + 1 rows, there's at least one more page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **Tuple comparison `(created_at, id) < ($1, $2)`** — PostgreSQL compares row constructors lexicographically, which is exactly the semantics we want for a compound `created_at DESC, id DESC` sort. It handles the tie-break on `id` correctly when multiple posts share the same `created_at`, and avoids the verbose `created_at < $1 OR (created_at = $1 AND id < $2)` form. For best performance, back it with a composite index: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;`
- **`base64url`** avoids `+`, `/`, and `=` characters that need URL-escaping in a query string.
- **Cursor validation** checks both decodability *and* shape, so a truncated, tampered, or random `after` value yields a clean 400 rather than a 500.
- **`limit` is clamped** (1–100) to prevent a client from requesting an unbounded page.

## Why cursor-based pagination is superior here

1. **Constant-time deep pagination.** `OFFSET 100000` forces Postgres to *scan and discard* 100k rows before returning the page — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` seeks directly into the index and reads only the rows it returns, so page 5,000 is as fast as page 1.

2. **No expensive COUNT.** On large tables `SELECT COUNT(*)` is a full scan/heavy index scan every request. Dropping it (and the `totalPages` it fed) removes that cost entirely.

3. **Stable results under concurrent writes.** With OFFSET, a row inserted or deleted between page loads shifts every subsequent row, causing items to be skipped or shown twice. A cursor anchors to a specific `(created_at, id)` position, so new posts at the top never corrupt the page boundary.

The trade-off: you lose random access to an arbitrary page number and a total count — which is the right call for a feed-style, scroll-forward `posts` listing.

